class CapitaStar:
    def __init__(self, phone: int, name: str):
        self._phone = phone
        self._name = name
        self._starDollars = 0

    @property
    def starDollars(self) -> int:
        return self._starDollars

    @starDollars.setter
    def starDollars(self, value: int):
        self._starDollars = value

    def addStarDollars(self, amountSpent: float):
        if amountSpent > 10:
            self._starDollars += int(amountSpent)  # floor: $21.60 earns 21 STAR$

    def redeemStarDollars(self, amount: int) -> bool:
        if self._starDollars >= amount:
            self._starDollars -= amount
            return True
        return False
