class BudgetPlan:
    TYPE_BUDGET = {
        'Food': 800,
        'Education': 500,
        'Travel': 300,
        'Others': 200
    }

    def __init__(self, capitaStar=None):
        self._expenses = []
        self._capitaStar = capitaStar

    def add(self, expense: Expense):
        # Check if adding this expense exceeds budget for this type
        current_total = sum(e.amount for e in self._expenses if e.expenseType == expense.expenseType)
        budget = BudgetPlan.TYPE_BUDGET[expense.expenseType]
        if current_total + expense.amount > budget:
            raise ExpenseException(
                f'Adding this expense exceeds the {expense.expenseType} budget of ${budget}'
            )
        # Credit STAR$ if applicable
        if self._capitaStar is not None and expense.isCapitaStar:
            self._capitaStar.addStarDollars(expense.amount)
        # Add to list
        self._expenses.append(expense)

    def listExpenses(self, expenseType=None) -> str:
        if expenseType is not None:
            # Validate type
            if expenseType not in BudgetPlan.TYPE_BUDGET:
                raise ExpenseException(f'Invalid expense type: {expenseType}')
            # Return matching expenses
            matching = [e for e in self._expenses if e.expenseType == expenseType]
            return '\n'.join(str(e) for e in matching)
        else:
            # Return all expenses
            result = '\n'.join(str(e) for e in self._expenses)
            if self._capitaStar is not None:
                result += f'\nSTAR$: {self._capitaStar.starDollars}'
            return result
