@classmethod
def updateBudgetByType(cls, type: str, budget: float):
    cls.TYPE_BUDGET[type] = budget
    # This handles both add (key doesn't exist) and update (key exists)
    # Dictionary assignment works for both cases

@classmethod
def listBudget(cls) -> str:
    lines = []
    for t, b in cls.TYPE_BUDGET.items():
        lines.append(f'{t:<12} ${b:.2f}')
    return '\n'.join(lines)
